CREATE TABLE `mx_user` (
  `user_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '生成日期',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最近编辑时间',
  `latest_checkup_date_time` datetime DEFAULT NULL COMMENT '最近检查日期',
  `name` varchar(24) DEFAULT '' COMMENT '姓名',
  `gender` int(1) DEFAULT '1' COMMENT '性别 1:男性 0:女性',
  `date_of_birth` date DEFAULT NULL COMMENT '出生年月',
  `age` int(11) DEFAULT NULL COMMENT '年龄',
  `phone_number` varchar(50) NOT NULL COMMENT '手机号码',
  `password` varchar(255) NOT NULL DEFAULT '' COMMENT '密码',
